finalProject.cssTemplate:
:root {
  --bg:             #f5f5f0;
  --surface:        #ffffff;
  --border:         #e2e2dc;
  --accent:         #4f8ef7;
  --accent-dark:    #2f6fd4;
  --green:          #34c97e;
  --red:            #f25c54;
  --text-primary:   #1a1a1a;
  --text-secondary: #6b6b6b;
  --text-muted:     #a0a0a0;
  --radius-card:    16px;
}
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
body { font-family: 'DM Sans', sans-serif; background-color: var(--bg); min-height: 100vh; display: flex; flex-direction: column; align-items: center; padding: 40px 16px 64px; color: var(--text-primary); }
header { text-align: center; margin-bottom: 32px; }
.game-title { font-size: 2rem; font-weight: 700; letter-spacing: -0.5px; color: var(--text-primary); }
.game-subtitle { font-size: 0.9rem; color: var(--text-muted); font-weight: 500; margin-top: 4px; }
.stats-bar { display: flex; gap: 12px; margin-bottom: 20px; }
.stat-box { background: var(--surface); border: 1.5px solid var(--border); border-radius: var(--radius-card); padding: 12px 28px; text-align: center; min-width: 100px; }
.stat-box--round { border-color: var(--accent); background: #f0f5ff; }
.stat-label { display: block; font-size: 0.65rem; font-weight: 700; text-transform: uppercase; letter-spacing: 1.2px; color: var(--text-muted); margin-bottom: 4px; }
.stat-number { display: block; font-family: 'DM Mono', monospace; font-size: 1.8rem; font-weight: 500; color: var(--text-primary); line-height: 1; }
.stat-box--round .stat-number { color: var(--accent); }
.status-message { font-size: 0.95rem; font-weight: 600; color: var(--text-secondary); background: var(--surface); border: 1.5px solid var(--border); border-radius: 50px; padding: 8px 22px; margin-bottom: 24px; min-height: 40px; display: flex; align-items: center; justify-content: center; }
.question-card { background: var(--surface); border: 1.5px solid var(--border); border-radius: var(--radius-card); padding: 32px 28px 28px; text-align: center; width: 100%; max-width: 360px; margin-bottom: 24px; }
.question-label { font-size: 0.75rem; font-weight: 700; text-transform: uppercase; letter-spacing: 1.5px; color: var(--text-muted); margin-bottom: 12px; }
.question-display { display: flex; align-items: center; justify-content: center; gap: 12px; margin-bottom: 24px; }
.q-num { font-family: 'DM Mono', monospace; font-size: 2.6rem; font-weight: 500; background: var(--bg); border: 1.5px solid var(--border); border-radius: 10px; padding: 6px 18px; color: var(--text-primary); min-width: 72px; text-align: center; }
.q-op { font-family: 'DM Mono', monospace; font-size: 2rem; color: var(--accent); font-weight: 500; }
.answer-input { width: 100%; font-family: 'DM Mono', monospace; font-size: 1.6rem; font-weight: 500; text-align: center; background: var(--bg); border: 1.5px solid var(--border); border-radius: 10px; padding: 10px; color: var(--text-primary); outline: none; margin-bottom: 12px; transition: border-color 0.15s; -moz-appearance: textfield; }
.answer-input::-webkit-inner-spin-button, .answer-input::-webkit-outer-spin-button { -webkit-appearance: none; }
.answer-input:focus { border-color: var(--accent); box-shadow: 0 0 0 3px rgba(79,142,247,0.15); }
.answer-input:disabled { opacity: 0.4; cursor: not-allowed; }
.check-btn { font-family: 'DM Sans', sans-serif; font-size: 0.95rem; font-weight: 700; background: var(--accent); color: #fff; border: none; border-radius: 50px; padding: 11px 32px; cursor: pointer; width: 100%; transition: background 0.15s, transform 0.1s; }
.check-btn:hover:not(:disabled) { background: var(--accent-dark); transform: translateY(-1px); }
.check-btn:disabled { opacity: 0.4; cursor: not-allowed; }
.start-btn { font-family: 'DM Sans', sans-serif; font-size: 1rem; font-weight: 700; background: var(--accent); color: #fff; border: none; border-radius: 50px; padding: 13px 40px; cursor: pointer; transition: background 0.15s ease, transform 0.1s ease; }
.start-btn:hover { background: var(--accent-dark); transform: translateY(-1px); }
.overlay { display: none; position: fixed; inset: 0; background: rgba(20,20,20,0.5); backdrop-filter: blur(6px); z-index: 100; align-items: center; justify-content: center; }
.overlay-box { background: var(--surface); border-radius: 20px; border: 1.5px solid var(--border); padding: 48px 40px 40px; text-align: center; max-width: 300px; width: 90%; animation: popIn 0.25s cubic-bezier(0.34,1.56,0.64,1); }
.overlay-eyebrow { font-size: 0.7rem; font-weight: 700; text-transform: uppercase; letter-spacing: 2px; color: var(--red); margin-bottom: 8px; }
.overlay-title { font-size: 1.1rem; font-weight: 500; color: var(--text-secondary); margin-bottom: 12px; }
.overlay-score-display { font-family: 'DM Mono', monospace; font-size: 3.5rem; font-weight: 500; color: var(--text-primary); line-height: 1; margin-bottom: 10px; }
.overlay-sub { font-size: 0.85rem; color: var(--text-muted); margin-bottom: 28px; }
.wrong-flash { display: none; position: fixed; inset: 0; background: rgba(242,92,84,0.2); z-index: 50; pointer-events: none; }
.wrong-flash.active { display: block; animation: flashFade 0.45s ease forwards; }
@keyframes popIn { from { transform: scale(0.85); opacity: 0; } to { transform: scale(1); opacity: 1; } }
@keyframes flashFade { from { opacity: 1; } to { opacity: 0; } }

challenges.starterCode:
// Global state
let score         = 0;
let round         = 1;
let isPlaying     = true;
let correctAnswer = 0;

// DOM references
const scoreDisplay   = document.getElementById('score-display');
const roundDisplay   = document.getElementById('round-display');
const statusMessage  = document.getElementById('status-message');
const numA           = document.getElementById('num-a');
const numB           = document.getElementById('num-b');
const answerInput    = document.getElementById('answer-input');
const checkBtn       = document.getElementById('check-btn');
const gameOverScreen = document.getElementById('game-over-screen');
const finalScore     = document.getElementById('final-score');
const wrongFlash     = document.getElementById('wrong-flash');

function generateQuestion() {
    let a = Math.floor(Math.random() * 10) + 1;
    let b = Math.floor(Math.random() * 10) + 1;
    numA.textContent = a;
    numB.textContent = b;
    return a + b;
}

function checkResult(playerAnswer, correctAns) {
    if (playerAnswer === correctAns) {
        return true;
    } else {
        return false;
    }
}

function handleOutcome(result) {
    if (result === true) {
        score = score + 1;
        round = round + 1;
        scoreDisplay.textContent = score;
        roundDisplay.textContent = round;
        statusMessage.textContent = 'Correct!';
        setTimeout(startRound, 800);
    } else {
        isPlaying = false;
        statusMessage.textContent = 'Wrong!';
        wrongFlash.classList.add('active');
        setTimeout(showGameOver, 600);
    }
}

function startRound() {
    if (isPlaying === false) { return; }
    statusMessage.textContent = 'Your turn!';
    answerInput.value = '';
    answerInput.disabled = false;
    checkBtn.disabled = false;
    correctAnswer = generateQuestion();
    answerInput.focus();
}

function handleClick() {
    let playerAnswer = Number(answerInput.value);
    checkBtn.disabled = true;
    answerInput.disabled = true;
    let result = checkResult(playerAnswer, correctAnswer);
    handleOutcome(result);
}

function showGameOver() {
    finalScore.textContent = score;
    gameOverScreen.style.display = 'flex';
}

checkBtn.addEventListener('click', handleClick);
document.getElementById('start-btn').addEventListener('click', function() {
    document.getElementById('start-btn').style.display = 'none';
    startRound();
});
document.getElementById('restart-btn').addEventListener('click', function() {
    score = 0; round = 1; isPlaying = true;
    scoreDisplay.textContent = 0;
    roundDisplay.textContent = 1;
    wrongFlash.classList.remove('active');
    gameOverScreen.style.display = 'none';
    startRound();
});

